const item = $input.first().json;
const textoPrePreenchido = `CAMPANHA-ID=${item.idCampanha}`;
const urlEncoded = encodeURIComponent(textoPrePreenchido);
const urlWhatsApp = `https://wa.me/${item.numeroEmpresa}?text=${urlEncoded}`;

return [{
  json: {
    ...item,
    urlWhatsApp,
    textoPrePreenchido
  }
}];

const raw = $input.first().json;

const payload = raw.body || raw;

const message = payload.message || {};
const chat = payload.chat || {};

const textoMsg = (typeof message === 'string')
  ? message
  : String(message.text || message.content || message.body || '');
const body = textoMsg.trim();

const fromRaw = String(
  chat.phone
  || chat.wa_chatid
  || message.chatid
  || message.sender_pn
  || ''
);
const telefone = fromRaw.replace(/@.*/, '').replace(/\D/g, '');

const nomeContato = String(
  chat.name
  || chat.wa_contactName
  || chat.wa_name
  || message.senderName
  || ''
);

const msgType = String(message.type || message.messageType || 'text').toLowerCase();
const eventType = String(payload.EventType || payload.event || '').toLowerCase();
const isFromMe = message.fromMe === true;

const isTexto = ['text', 'conversation', 'extendedtextmessage'].includes(msgType);
const isEvento = eventType === 'messages' || eventType === 'message' || eventType === 'messages.upsert';

const matchCampanha = body.match(/CAMPANHA-ID[=:]\s*(\S+)/i);
const idCampanha = matchCampanha ? matchCampanha[1] : null;

const valido = !!(
  telefone
  && telefone.length >= 10
  && idCampanha
  && isTexto
  && isEvento
  && !isFromMe
);
const temTelefone = !!(telefone && telefone.length >= 10 && !isFromMe);

return [{
  json: {
    telefone,
    nomeContato,
    idCampanha,
    textoOriginal: body,
    evento: eventType,
    tipoMensagem: msgType,
    messageId: message.messageid || message.id || '',
    isFromMe,
    valido,
    temTelefone,
    instanceName: payload.instanceName || '',
    timestamp: new Date().toISOString()
  }
}];

const idCampanha = $input.first().json.idCampanha;

const campanhas = {
  'BLACKFRIDAY2026': {
    nome: 'Black Friday 2026',
    cupom: 'BF2026-30OFF',
    desconto: '30%',
    expiracao: '01/12/2026',
    ativa: true
  },
  'NATAL2026': {
    nome: 'Natal 2026',
    cupom: 'NATAL2026-25OFF',
    desconto: '25%',
    expiracao: '25/12/2026',
    ativa: true
  }
};

const campanha = campanhas[idCampanha] || null;

if (!campanha) {
  return [{ json: { ...$input.first().json, campanhaEncontrada: false, campanhaAtiva: false } }];
}

if (!campanha.ativa) {
  return [{ json: { ...$input.first().json, campanhaEncontrada: true, campanhaAtiva: false, nomeCampanha: campanha.nome } }];
}

return [{
  json: {
    ...$input.first().json,
    campanhaEncontrada: true,
    campanhaAtiva: true,
    nomeCampanha: campanha.nome,
    cupom: campanha.cupom,
    desconto: campanha.desconto,
    expiracao: campanha.expiracao
  }
}];

